import type * as React from 'react';
import type { Slot } from '../shared/slot';
import type { DownloadProps } from './components/Download';

/** 控制工具栏的展示 */
export interface ImageViewerToolbarProps extends React.ComponentPropsWithRef<'div'> {
  /** 是否显示工具栏-翻页
   * @defaultValue true
   */
  pagination?: boolean;
  /** 是否显示工具栏-缩放
   *  @defaultValue true
   */
  scaling?: boolean;
  /** 是否显示工具栏-翻转
   *  @defaultValue true
   */
  rotation?: boolean;
  /** 是否显示/自定义工具栏-下载
   *  @defaultValue true
   */
  download?: boolean | Slot<DownloadProps>;
}

export interface UseImageViewerToolbarProps {
  /**
   * 控制工具栏的展示
   * @defaultValue true
   */
  toolbar?: ImageViewerToolbarProps | boolean;
  /**
   * 自定义 toolbar 插件
   */
  plugins?: React.ReactElement[];
}
